import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';

const WORKER_ID = Deno.env.get('WORKER_ID') || `refine_worker_${Math.random().toString(36).substring(7)}`;
const AI_TIMEOUT = 120000;
const COOLDOWN_DURATION = 60 * 60 * 1000;

async function runRefinement() {
  const supabase = createClient(Deno.env.get('SUPABASE_URL')!, Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!);

  console.log(`\n======================================================`);
  console.log(`🚀 [REFINE BATCH] ID: ${WORKER_ID} | Timestamp: ${new Date().toISOString()}`);
  console.log(`======================================================`);

  for (let cycle = 1; cycle <= 10; cycle++) {
    let batchJobs = [];
    try {
      console.log(`\n>>> [CYCLE ${cycle}/10] Requesting Batch...`);
      const { data: packet, error: rpcErr } = await supabase.rpc('get_refinement_work_batch', { p_worker_id: WORKER_ID });

      if (rpcErr) throw new Error(`RPC Failed: ${rpcErr.message}`);
      if (!packet || packet.error === 'NO_WORK') break;
      if (packet.error === 'NO_API_KEY') {
        await new Promise(r => setTimeout(r, 30000));
        continue;
      }

      const { batch, api_key, key_id, total_word_count } = packet;
      batchJobs = batch;

      console.log(`[BATCH] Collected ${batch.length} roots | Total words: ${total_word_count}`);

      // Format input for AI with nested identifiers (Root R, Variation R.V)
      let promptInput = "";
      batch.forEach((item: any, rIdx: number) => {
        promptInput += `\nROOT ${rIdx}: ${item.root}\nVARIATIONS ${rIdx}:\n`;
        (item.variations || []).forEach((v: any, vIdx: number) => {
          promptInput += `${rIdx}.${vIdx}. ${v.word}\n`;
        });
      });

      const systemInstruction = `
        ROLE: Expert Amharic Ethiopic Linguistic Auditor.
        MISSION: Perform high-fidelity audits on a batch of multiple Master Roots and their Variation lists.

        PART 1: ROOT AUDITS
        Standard: The root MUST be the ABSOLUTE GENERIC INFINITIVE or CITATION form (መነሻ ቃል).
        - PROTECT NATURALIZED NOUNS: Do NOT reject words like 'ሎሚ', 'ባልዲ', 'ሳሙና', 'ሃቅ/ሐቅ', 'ሌማት', 'መጽሐፍ'. They are valid roots.
        - REJECT TRASH: Reject specific proper names (ዮሐንስ), cities (አዲስ አበባ), or modern transliterations (ኮምፒውተር, ኢንተርኔት).
        - STANDARDIZE: For verbs, prefer infinitives (መ-). Correct ሀ/ሃ/ሐ typos.

        PART 2: VARIATIONS AUDIT
        - Each variation belongs to its specific root if it's a valid conjugation or derivation.
        - Typo Correction: Flag true, provide 'correction'.

        OUTPUT FORMAT: Return a single JSON array of Audit Results corresponding to the Root index.\n\n        [
          {
            "root_index": 0,
            "root_audit": { "is_root": boolean, "real_root": string|null },
            "variation_audit": [
              { "id": "0.0", "belongs": boolean, "correction": string|null },
              { "id": "0.1", "belongs": boolean, "correction": string|null }
            ]
          },
          ...for each root...
        ]`;

      let batchResults = null;
      for (let attempt = 1; attempt <= 3; attempt++) {
        const aiResp = await fetch("https://generativelanguage.googleapis.com/v1beta/models/gemini-3.1-flash-lite-preview:generateContent?key=" + api_key, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            contents: [{ parts: [{ text: `SYSTEM: ${systemInstruction}\n\nDATA TO AUDIT:\n${promptInput}` }] }],
            generationConfig: { responseMimeType: 'application/json', temperature: 0.1 }
          })
        });

        if (aiResp.status === 429) {
          await supabase.from('api_keys').update({ cooldown_until: new Date(Date.now() + COOLDOWN_DURATION).toISOString() }).eq('id', key_id);
          throw new Error("RATE_LIMIT");
        }

        const result = await aiResp.json();
        const rawText = result.candidates?.[0]?.content?.parts?.[0]?.text || "";
        try {
          batchResults = JSON.parse(rawText.match(/\\[[\\s\\S]*\\]/)?.[0] || rawText);
          break;
        } catch (e) { if (attempt === 3) throw new Error("AI_PARSE_FAILED"); }
        await new Promise(r => setTimeout(r, 2000 * attempt));
      }

      // PROCESS BATCH RESULTS
      for (const item of batch) {
        const rootIdx = batch.indexOf(item);
        const audit = batchResults.find((a: any) => a.root_index === rootIdx);

        if (audit) {
           await supabase.from('refinement_audit_logs').insert({
             job_id: item.job_id,
             original_root: item.root,
             original_vars_count: item.variations?.length || 0,
             ai_raw_response: audit,
             worker_id: WORKER_ID
           });
           console.log(`[AUDITED] Root ${item.root} recorded in batch.`);
        }
        await supabase.rpc('mark_validation_done', { p_job_id: item.job_id });
      }

    } catch (err) {
      console.error(`[CRITICAL] Error in batch cycle: ${err.message}`);
      for (const item of batchJobs) {
        await supabase.rpc('fail_validation_work', { p_job_id: item.job_id, p_error: err.message });
      }
      await new Promise(r => setTimeout(r, 10000));
    }
  }
  console.log(`🛑 [WORKER ENDED]`);
}

runRefinement();

